11918     case RecurKind::Or:
11919       if (UseSelect &&
11920           LHS->getType() == CmpInst::makeCmpResultType(LHS->getType()))
11921         return Builder.CreateSelect(LHS, Builder.getTrue(), RHS, Name);
11922       return Builder.CreateBinOp((Instruction::BinaryOps)RdxOpcode, LHS, RHS,
11923                                  Name);
11924     case RecurKind::And:
11925       if (UseSelect &&
11926           LHS->getType() == CmpInst::makeCmpResultType(LHS->getType()))
11927         return Builder.CreateSelect(LHS, RHS, Builder.getFalse(), Name);
11928       return Builder.CreateBinOp((Instruction::BinaryOps)RdxOpcode, LHS, RHS,
11929                                  Name);
11930     case RecurKind::Add:
11931     case RecurKind::Mul:
11932     case RecurKind::Xor:
11933     case RecurKind::FAdd:
11934     case RecurKind::FMul:
11935       return Builder.CreateBinOp((Instruction::BinaryOps)RdxOpcode, LHS, RHS,
11936                                  Name);
11937     case RecurKind::FMax:
11938       return Builder.CreateBinaryIntrinsic(Intrinsic::maxnum, LHS, RHS);
11939     case RecurKind::FMin:
11940       return Builder.CreateBinaryIntrinsic(Intrinsic::minnum, LHS, RHS);
11941     case RecurKind::SMax:
11942       if (UseSelect) {
11943         Value *Cmp = Builder.CreateICmpSGT(LHS, RHS, Name);
11944         return Builder.CreateSelect(Cmp, LHS, RHS, Name);
11945       }
11946       return Builder.CreateBinaryIntrinsic(Intrinsic::smax, LHS, RHS);
11947     case RecurKind::SMin:
11948       if (UseSelect) {
11949         Value *Cmp = Builder.CreateICmpSLT(LHS, RHS, Name);
11950         return Builder.CreateSelect(Cmp, LHS, RHS, Name);
11951       }
11952       return Builder.CreateBinaryIntrinsic(Intrinsic::smin, LHS, RHS);
11953     case RecurKind::UMax:
11954       if (UseSelect) {
11955         Value *Cmp = Builder.CreateICmpUGT(LHS, RHS, Name);
11956         return Builder.CreateSelect(Cmp, LHS, RHS, Name);
11957       }
11958       return Builder.CreateBinaryIntrinsic(Intrinsic::umax, LHS, RHS);
11959     case RecurKind::UMin:
11960       if (UseSelect) {
11961         Value *Cmp = Builder.CreateICmpULT(LHS, RHS, Name);
11962         return Builder.CreateSelect(Cmp, LHS, RHS, Name);
11963       }
11964       return Builder.CreateBinaryIntrinsic(Intrinsic::umin, LHS, RHS);
