13134   /// Emits actual operation for the scalar identity values, found during
13135   /// horizontal reduction analysis.
13136   Value *emitReusedOps(Value *VectorizedValue, IRBuilderBase &Builder,
13137                        ArrayRef<Value *> VL,
13138                        const MapVector<Value *, unsigned> &SameValuesCounter,
13139                        const DenseMap<Value *, Value *> &TrackedToOrig) {
13140     assert(IsSupportedHorRdxIdentityOp &&
13141            "The optimization of matched scalar identity horizontal reductions "
13142            "must be supported.");
13143     switch (RdxKind) {
13144     case RecurKind::Add: {
13145       // root = mul prev_root, <1, 1, n, 1>
13146       SmallVector<Constant *> Vals;
