13148         unsigned Cnt = SameValuesCounter.lookup(TrackedToOrig.find(V)->second);
13149         Vals.push_back(ConstantInt::get(V->getType(), Cnt, /*IsSigned=*/false));
13150       }
13151       auto *Scale = ConstantVector::get(Vals);
13152       LLVM_DEBUG(dbgs() << "SLP: Add (to-mul) " << Scale << "of "
13153                         << VectorizedValue << ". (HorRdx)\n");
13154       return Builder.CreateMul(VectorizedValue, Scale);
13155     }
13156     case RecurKind::And:
13157     case RecurKind::Or:
13158       // No need for multiple or/and(s).
13159       LLVM_DEBUG(dbgs() << "SLP: And/or of same " << VectorizedValue
13160                         << ". (HorRdx)\n");
