13162     case RecurKind::SMax:
13163     case RecurKind::SMin:
13164     case RecurKind::UMax:
13165     case RecurKind::UMin:
13166     case RecurKind::FMax:
13167     case RecurKind::FMin:
13168       // No need for multiple min/max(s) of the same value.
13169       LLVM_DEBUG(dbgs() << "SLP: Max/min of same " << VectorizedValue
13170                         << ". (HorRdx)\n");
13171       return VectorizedValue;
