13173       // Replace values with even number of repeats with 0, since
13174       // x xor x = 0.
13175       // root = shuffle prev_root, zeroinitalizer, <0, 1, 2, vf, 4, vf, 5, 6,
13176       // 7>, if elements 4th and 6th elements have even number of repeats.
13177       SmallVector<int> Mask(
13178           cast<FixedVectorType>(VectorizedValue->getType())->getNumElements(),
