13180       std::iota(Mask.begin(), Mask.end(), 0);
13181       bool NeedShuffle = false;
13182       for (unsigned I = 0, VF = VL.size(); I < VF; ++I) {
13183         Value *V = VL[I];
13184         unsigned Cnt = SameValuesCounter.lookup(TrackedToOrig.find(V)->second);
