13199     }
13200     case RecurKind::FAdd: {
13201       // root = fmul prev_root, <1.0, 1.0, n.0, 1.0>
13202       SmallVector<Constant *> Vals;
13203       for (Value *V : VL) {
13204         unsigned Cnt = SameValuesCounter.lookup(TrackedToOrig.find(V)->second);
